Greedy insertion with cost‑delta evaluation across all existing routes and a fallback empty assign creation for each unplaceable order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	if nOrders == 0 || len(dess) != nOrders {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type trialResult struct {
		assignIdx int
		costDelta float64
		ok        bool
	}
	const INVALID_DELTA = 1e100
	// Process each order sequentially
	for oIdx := 0; oIdx < nOrders; oIdx++ {
		id := total_ship + oIdx
		ori := oris[oIdx]
		des := dess[oIdx]
		bestRes := trialResult{-1, INVALID_DELTA, false}
		// Try every existing non-empty assign plus the first empty slot within current length
		maxTryAssign := dispatch.AssignsLen
		for ai := 0; ai < maxTryAssign; ai++ {
			asgn := &dispatch.Assigns[ai]
			origCost := asgn.Cost
			// Save stations snapshot (we rely on RemoveShip/GenRoute for rollback)
			ok := asgn.AddShip(id, ori, des)
			if !ok {
				continue
			}
			asgn.GenRoute()
			newCost := asgn.Cost
			if newCost >= 0 {
				delta := newCost - origCost
				if delta < bestRes.costDelta {
					bestRes.assignIdx = ai
					bestRes.costDelta = delta
					bestRes.ok = true
				}
			}
			// Rollback trial
			asgn.RemoveShip(id)
			asgn.GenRoute()
		}
		// Also try appending a brand-new assign at dispatch.AssignsLen (if space allows)
		if !bestRes.ok || dispatch.AssignsLen < MAXASSIGNS {
			ai := dispatch.AssignsLen
			asgn := &dispatch.Assigns[ai]
			origCost := asgn.Cost
			ok := asgn.AddShip(id, ori, des)
			if ok {
				asgn.GenRoute()
				newCost := asgn.Cost
				if newCost >= 0 {
					delta := newCost - origCost
					if delta < bestRes.costDelta {
						bestRes.assignIdx = ai
						bestRes.costDelta = delta
						bestRes.ok = true
					}
				}
				// Keep rolled-back if we later choose another assign; otherwise keep
				asgn.RemoveShip(id)
				asgn.GenRoute()
			}
		}
		// Commit the best insertion found
		if bestRes.ok {
			targetAsgn := &dispatch.Assigns[bestRes.assignIdx]
			targetAsgn.AddShip(id, ori, des)
			targetAsgn.GenRoute()
			// Extend assignsLen if we used a fresh assign
			if bestRes.assignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestRes.assignIdx + 1
			}
		} else {
			// Fallback safe seed: create a new assign even if it may increase total vehicles
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				asgn := &dispatch.Assigns[fallbackIdx]
				ok := asgn.AddShip(id, ori, des)
				if ok {
					asgn.GenRoute()
					if asgn.Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						// Should not happen per problem guarantee, but clean up
						asgn.RemoveShip(id)
						asgn.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

